#include <stdio.h>
int main() {
    int T, K;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &K);
        char grid[8][8];
        for (int i = 0; i < 8; i++) {
            for (int j = 0; j < 8; j++) {
                grid[i][j] = '.';
            }
        }
        grid[4][4] = 'O';
        int reachable = 0;
        for (int i = 0; i < 8; i++) {
            for (int j = 0; j < 8; j++) {
                if (i == 4 && j == 4) continue;
                if (abs(i - 4) <= 1 && abs(j - 4) <= 1) reachable++;
            }
        }
        while (reachable < K) {
            for (int i = 0; i < 8; i++) {
                for (int j = 0; j < 8; j++) {
                    if (grid[i][j] == 'X') {
                        grid[i][j] = '.';
                        reachable++;
                        break;
                    }
                }
                if (reachable >= K) break;
            }
        }
        while (reachable > K) {
            for (int i = 0; i < 8; i++) {
                for (int j = 0; j < 8; j++) {
                    if (grid[i][j] == '.') {
                        grid[i][j] = 'X';
                        reachable--;
                        break;
                    }
                }
                if (reachable <= K) break;
            }
        }
        for (int i = 0; i < 8; i++) {
            for (int j = 0; j < 8; j++) {
                printf("%c", grid[i][j]);
            }
            printf("\n");
        }
    }
    return 0;
}

